{"path": "/tmp/sv-248d07bca7364bffb814acab971362aa/Components/Catalog/CatalogPagination.razor", "file_text": "@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page - 1))" disabled="@(Page <= 1)">Previous</button>
            </li>
            @foreach (var p in GetPageNumbers())
            {
                <li class="page-item @(p == Page ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(p))">@p</button>
                </li>
            }
            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page + 1))" disabled="@(Page >= TotalPages)">Next</button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int Page { get; set; } = 1;
    [Parameter] public int TotalPages { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 5;
        int start = Math.Max(1, Page - maxVisible / 2);
        int end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}
"}

{"path": "/tmp/sv-248d07bca7364bffb814acab971362aa/Components/Pages/Catalog.razor", "file_text": "@page "/catalog"
@using sv_248d07bca7364bffb814acab971362aa.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogFilters Categories="categories"
                            OnFiltersApplied="HandleFiltersApplied"
                            OnFiltersCleared="HandleFiltersCleared" />
        </div>

        <div class="col-md-9">
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="totalCount"
                            Page="currentPage"
                            PageSize="pageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (isLoading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (products.Count == 0)
            {
                <div class="text-center py-5 text-muted">
                    <p class="fs-5">No products found</p>
                    <p>Try adjusting your filters or clearing them.</p>
                </div>
            }
            else
            {
                <ProductGrid Products="products"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />
            }

            <CatalogPagination Page="currentPage"
                               TotalPages="totalPages"
                               OnPageChanged="HandlePageChanged" />
        </div>
    </div>
}

@code {
    /// <summary>Raised when a product card is clicked so the parent or router can navigate to a detail page.</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<Product> products = [];
    private List<string> categories = [];
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private int pageSize = 12;
    private int totalCount;
    private int totalPages;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            categories = await categoriesTask;
            var result = await productsTask;

            products = result.Items;
            totalCount = result.TotalCount;
            totalPages = (int)Math.Ceiling((double)result.TotalCount / pageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);

            products = result.Items;
            totalCount = result.TotalCount;
            totalPages = (int)Math.Ceiling((double)result.TotalCount / pageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFiltersCleared()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}
"}

